@* Step indicator bar showing progress through the application steps *@

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var status = step < CurrentStep ? "completed" : step == CurrentStep ? "active" : "future";
            <li class="step-item @status">
                @if (step < CurrentStep)
                {
                    <button class="step-button" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-circle">✓</span>
                        <span class="step-label">@StepNames[step]</span>
                    </button>
                }
                else
                {
                    <span class="step-button" aria-current="@(step == CurrentStep ? "step" : null)">
                        <span class="step-circle">@(step + 1)</span>
                        <span class="step-label">@StepNames[step]</span>
                    </span>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

nav.step-indicator {
    background: #f8f9fa;
    border-radius: 8px;
    padding: 1rem;
}

ol.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    justify-content: space-between;
    position: relative;
}

li.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
}

/* Connector line between steps */
li.step-item:not(:last-child)::after {
    content: '';
    position: absolute;
    top: 16px;
    left: calc(50% + 18px);
    width: calc(100% - 36px);
    height: 2px;
    background: #dee2e6;
}

li.step-item.completed:not(:last-child)::after {
    background: #198754;
}

.step-button {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    background: none;
    border: none;
    cursor: default;
    padding: 0;
    font: inherit;
    color: inherit;
}

li.completed .step-button {
    cursor: pointer;
}

li.completed .step-button:hover .step-label {
    text-decoration: underline;
}

.step-circle {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.85rem;
    position: relative;
    z-index: 1;
}

li.future .step-circle {
    background: #dee2e6;
    color: #6c757d;
}

li.active .step-circle {
    background: #0d6efd;
    color: white;
}

li.completed .step-circle {
    background: #198754;
    color: white;
}

.step-label {
    font-size: 0.8rem;
    text-align: center;
    white-space: nowrap;
}

li.future .step-label {
    color: #adb5bd;
}

li.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

li.completed .step-label {
    color: #198754;
}

