+li.step-item:not(:last-child)::after {
+    content: '';
+    position: absolute;
+    top: 16px;
+    left: calc(50% + 18px);
+    width: calc(100% - 36px);
+    height: 2px;
+    background: #dee2e6;
+}
+
+li.step-item.completed:not(:last-child)::after {
+    background: #198754;
+}
+
+.step-button {
+    display: flex;
+    flex-direction: column;
+    align-items: center;
+    gap: 0.5rem;
+    background: none;
+    border: none;
+    cursor: default;
+    padding: 0;
+    font: inherit;
+    color: inherit;
+}
+
+li.completed .step-button {
+    cursor: pointer;
+}
+
+li.completed .step-button:hover .step-label {
+    text-decoration: underline;
+}
+
+.step-circle {
+    width: 32px;
+    height: 32px;
+    border-radius: 50%;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    font-weight: 600;
+    font-size: 0.85rem;
+    position: relative;
+    z-index: 1;
+}
+
+li.future .step-circle {
+    background: #dee2e6;
+    color: #6c757d;
+}
+
+li.active .step-circle {
+    background: #0d6efd;
+    color: white;
+}
+
+li.completed .step-circle {
+    background: #198754;
+    color: white;
+}
+
+.step-label {
+    font-size: 0.8rem;
+    text-align: center;
+    white-space: nowrap;
+}
+
+li.future .step-label {
+    color: #adb5bd;
+}
+
+li.active .step-label {
+    color: #0d6efd;
+    font-weight: 600;
+}
+
+li.completed .step-label {
+    color: #198754;
+}
