@* Step 1 — Personal Info form *@

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">Personal Information</h4>

        <div class="mb-3">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input class="form-control" @bind="Model.FullName" @bind:event="oninput" placeholder="Jane Doe" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control @(emailError is not null ? "is-invalid" : "")"
                   @bind="Model.Email" @bind:event="oninput" placeholder="jane@example.com" />
            @if (emailError is not null)
            {
                <div class="invalid-feedback">@emailError</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
        </div>

        <div class="mb-3">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <textarea class="form-control" rows="2" @bind="Model.Address" @bind:event="oninput"
                      placeholder="123 Main St, City, State ZIP"></textarea>
        </div>

        @if (validationError is not null)
        {
            <div class="alert alert-danger py-2">@validationError</div>
        }

        <div class="d-flex justify-content-end">
            <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
                @if (isValidating)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                    <text>Validating…</text>
                }
                else
                {
                    <text>Next →</text>
                }
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private string? validationError;
    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        validationError = null;
        emailError = null;

        if (!Model.IsValid)
        {
            validationError = "Please fill in all required fields.";
            return;
        }

        isValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                emailError = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

@* Step 2 — Work History *@

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">Work History</h4>

        @for (int i = 0; i < Entries.Count; i++)
        {
            var index = i;
            <WorkEntryForm Model="Entries[index]"
                           Index="index"
                           CanRemove="Entries.Count > 1"
                           OnRemove="() => RemoveEntry(index)" />
        }

        <button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
            + Add Another Position
        </button>

        @if (validationError is not null)
        {
            <div class="alert alert-danger py-2">@validationError</div>
        }

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        validationError = null;

        if (Entries.Any(e => !e.IsValid))
        {
            validationError = "Please complete all required fields for each position.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

@* Step 3 — References *@

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">References</h4>

        @for (int i = 0; i < References.Count; i++)
        {
            var index = i;
            <ReferenceForm Model="References[index]"
                           Index="index"
                           CanRemove="References.Count > 2"
                           OnRemove="() => RemoveReference(index)" />
        }

        @if (References.Count < 3)
        {
            <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
                + Add Reference
            </button>
        }

        @if (validationError is not null)
        {
            <div class="alert alert-danger py-2">@validationError</div>
        }

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        validationError = null;

        if (References.Any(r => !r.IsValid))
        {
            validationError = "Please complete all required fields for each reference.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

@* Step 4 — Cover Letter *@

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">Cover Letter</h4>

        <div class="mb-3">
            <textarea class="form-control" rows="12" maxlength="@MaxLength"
                      @bind="CoverLetter" @bind:event="oninput"
                      placeholder="Tell us why you're a great fit for this role…"></textarea>
            <div class="form-text text-end">
                @CoverLetter.Length / @MaxLength characters
            </div>
        </div>

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
            <button class="btn btn-primary" @onclick="OnNext">Next →</button>
        </div>
    </div>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
}

@* Step 5 — Review & Submit *@

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-4">Review Your Application</h4>

        @if (IsSubmitted)
        {
            <div class="alert alert-success text-center py-4">
                <h5 class="mb-2">🎉 Application Submitted!</h5>
                <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
            </div>
        }
        else
        {
            @* Personal Info Section *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Personal Information</h5>
                    <button class="btn btn-sm btn-link" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
                </div>
                <dl class="row mb-0">
                    <dt class="col-sm-3">Name</dt>
                    <dd class="col-sm-9">@Personal.FullName</dd>
                    <dt class="col-sm-3">Email</dt>
                    <dd class="col-sm-9">@Personal.Email</dd>
                    <dt class="col-sm-3">Phone</dt>
                    <dd class="col-sm-9">@Personal.Phone</dd>
                    <dt class="col-sm-3">Address</dt>
                    <dd class="col-sm-9">@Personal.Address</dd>
                </dl>
                <hr />
            </div>

            @* Work History Section *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Work History</h5>
                    <button class="btn btn-sm btn-link" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
                </div>
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-2 ps-3 border-start border-3">
                        <strong>@entry.Title</strong> at @entry.Company<br />
                        <small class="text-muted">
                            @entry.StartDate.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                        </small>
                        <p class="mb-1 mt-1">@entry.Description</p>
                    </div>
                }
                <hr />
            </div>

            @* References Section *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">References</h5>
                    <button class="btn btn-sm btn-link" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
                </div>
                @foreach (var r in References)
                {
                    <div class="mb-2 ps-3 border-start border-3">
                        <strong>@r.Name</strong> — @r.Relationship<br />
                        <small class="text-muted">@r.Email · @r.Phone</small>
                    </div>
                }
                <hr />
            </div>

            @* Cover Letter Section *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Cover Letter</h5>
                    <button class="btn btn-sm btn-link" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
                </div>
                <p class="ps-3" style="white-space: pre-wrap;">@CoverLetter</p>
            </div>

            @if (submitError is not null)
            {
                <div class="alert alert-danger py-2">@submitError</div>
            }

            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
                <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
                    @if (isSubmitting)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                        <text>Submitting…</text>
                    }
                    else
                    {
                        <text>Submit Application</text>
                    }
                </button>
            </div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";

    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int? ApplicationId { get; set; }

    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private bool isSubmitting;
    private string? submitError;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

