<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-4">Review Your Application</h4>

        @if (IsSubmitted)
        {
            <div class="alert alert-success text-center py-4">
                <h5 class="mb-2">🎉 Application Submitted!</h5>
                <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
            </div>
        }
        else
        {
            @* Personal Info Section *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Personal Information</h5>
                    <button class="btn btn-sm btn-link" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
                </div>
                <dl class="row mb-0">
                    <dt class="col-sm-3">Name</dt>
                    <dd class="col-sm-9">@Personal.FullName</dd>
                    <dt class="col-sm-3">Email</dt>
                    <dd class="col-sm-9">@Personal.Email</dd>
                    <dt class="col-sm-3">Phone</dt>
                    <dd class="col-sm-9">@Personal.Phone</dd>
                    <dt class="col-sm-3">Address</dt>
                    <dd class="col-sm-9">@Personal.Address</dd>
                </dl>
                <hr />
            </div>

            @* Work History Section *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Work History</h5>
                    <button class="btn btn-sm btn-link" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
                </div>
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-2 ps-3 border-start border-3">
                        <strong>@entry.Title</strong> at @entry.Company<br />
                        <small class="text-muted">
                            @entry.StartDate.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                        </small>
                        <p class="mb-1 mt-1">@entry.Description</p>
                    </div>
                }
                <hr />
            </div>

            @* References Section *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">References</h5>
                    <button class="btn btn-sm btn-link" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
                </div>
                @foreach (var r in References)
                {
                    <div class="mb-2 ps-3 border-start border-3">
                        <strong>@r.Name</strong> — @r.Relationship<br />
                        <small class="text-muted">@r.Email · @r.Phone</small>
                    </div>
                }
                <hr />
            </div>

            @* Cover Letter Section *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Cover Letter</h5>
                    <button class="btn btn-sm btn-link" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
                </div>
                <p class="ps-3" style="white-space: pre-wrap;">@CoverLetter</p>
            </div>

            @if (submitError is not null)
            {
                <div class="alert alert-danger py-2">@submitError</div>
            }

            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
                <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
                    @if (isSubmitting)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                        <text>Submitting…</text>
                    }
                    else
                    {
                        <text>Submit Application</text>
                    }
                </button>
            </div>
        }
    </div>
</div>

