@page "/apply"
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personalInfo" OnNext="NextStep" />
            break;
        case 1:
            <WorkHistoryStep Entries="workEntries" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="references" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep @bind-CoverLetter="coverLetter" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        IsSubmitted="isSubmitted"
                        ApplicationId="applicationId"
                        OnBack="PreviousStep"
                        OnEditStep="GoToStep"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int currentStep;
    private bool isSubmitted;
    private int? applicationId;

    // Form state — owned by this page, passed down to step components
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private void NextStep() => currentStep++;

    private void PreviousStep() => currentStep--;

    private void GoToStep(int step)
    {
        if (step < currentStep)
        {
            currentStep = step;
        }
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter
        );

        applicationId = await ApplicationService.SubmitApplicationAsync(application);
        isSubmitted = true;
    }
}

